class Solution:
    def findMinHeightTrees(self, n: int, edges: List[List[int]]) -> List[int]:
        if n <= 2:
            return list(range(n))
        adj = [[] for _ in range(n)]
        deg = [0]*n
        for u, v in edges:
            adj[u].append(v); adj[v].append(u)
            deg[u] += 1; deg[v] += 1
        q = [i for i in range(n) if deg[i] == 1]
        rem = n
        while rem > 2:
            rem -= len(q)
            nxt = []
            for u in q:
                for v in adj[u]:
                    deg[v] -= 1
                    if deg[v] == 1:
                        nxt.append(v)
            q = nxt
        return q

